(() => {
  const win = window;
  const timelines = new Set();
  const baseCache = new WeakMap();
  const transformProps = new Set(["x", "y", "scale", "scaleX", "scaleY", "rotation"]);
  const reserved = new Set([
    "duration",
    "delay",
    "ease",
    "stagger",
    "onUpdate",
    "onComplete",
    "onStart",
    "overwrite",
    "repeat",
    "repeatDelay",
    "yoyo",
    "paused",
    "id",
    "defaults",
    "callbackScope",
    "immediateRender",
  ]);

  function clamp(value, min, max) {
    return Math.min(max, Math.max(min, value));
  }

  function isElement(target) {
    return !!target && target.nodeType === 1;
  }

  function toArray(target) {
    if (typeof target === "string") return Array.from(document.querySelectorAll(target));
    if (!target) return [];
    if (Array.isArray(target)) return target.flatMap((item) => toArray(item));
    if (typeof target.length === "number" && !target.nodeType && target !== win) return Array.from(target);
    return [target];
  }

  function parseNumberUnit(value) {
    if (typeof value === "number" && Number.isFinite(value)) return { value, unit: "" };
    if (typeof value !== "string") return null;
    const match = value.trim().match(/^(-?\d*\.?\d+)([a-z%]*)$/i);
    if (!match) return null;
    return { value: Number(match[1]), unit: match[2] || "" };
  }

  function parseColor(value) {
    if (typeof value !== "string") return null;
    const input = value.trim().toLowerCase();
    if (!input || input === "none") return null;
    if (input === "transparent") return { r: 0, g: 0, b: 0, a: 0 };
    const hex = input.match(/^#([0-9a-f]{3,8})$/i);
    if (hex) {
      const raw = hex[1];
      if (raw.length === 3 || raw.length === 4) {
        const r = parseInt(raw[0] + raw[0], 16);
        const g = parseInt(raw[1] + raw[1], 16);
        const b = parseInt(raw[2] + raw[2], 16);
        const a = raw.length === 4 ? parseInt(raw[3] + raw[3], 16) / 255 : 1;
        return { r, g, b, a };
      }
      if (raw.length === 6 || raw.length === 8) {
        const r = parseInt(raw.slice(0, 2), 16);
        const g = parseInt(raw.slice(2, 4), 16);
        const b = parseInt(raw.slice(4, 6), 16);
        const a = raw.length === 8 ? parseInt(raw.slice(6, 8), 16) / 255 : 1;
        return { r, g, b, a };
      }
    }
    const rgba = input.match(
      /^rgba?\(\s*([-\d.]+)\s*,\s*([-\d.]+)\s*,\s*([-\d.]+)(?:\s*,\s*([-\d.]+))?\s*\)$/
    );
    if (rgba) {
      return {
        r: Number(rgba[1]),
        g: Number(rgba[2]),
        b: Number(rgba[3]),
        a: rgba[4] == null ? 1 : Number(rgba[4]),
      };
    }
    return null;
  }

  function colorToString(color) {
    const r = Math.round(clamp(color.r, 0, 255));
    const g = Math.round(clamp(color.g, 0, 255));
    const b = Math.round(clamp(color.b, 0, 255));
    const a = clamp(color.a == null ? 1 : color.a, 0, 1);
    return a >= 1 ? `rgb(${r}, ${g}, ${b})` : `rgba(${r}, ${g}, ${b}, ${a})`;
  }

  function parseTransform(value) {
    if (!value || value === "none") {
      return { x: 0, y: 0, scaleX: 1, scaleY: 1, rotation: 0 };
    }
    const matrix = value.match(/^matrix\(([^)]+)\)$/);
    if (matrix) {
      const parts = matrix[1].split(",").map((n) => Number(n.trim()));
      const [a, b, c, d, e, f] = parts;
      return {
        x: Number.isFinite(e) ? e : 0,
        y: Number.isFinite(f) ? f : 0,
        scaleX: Math.hypot(a || 1, b || 0) || 1,
        scaleY: Math.hypot(c || 0, d || 1) || 1,
        rotation: (Math.atan2(b || 0, a || 1) * 180) / Math.PI,
      };
    }
    const matrix3d = value.match(/^matrix3d\(([^)]+)\)$/);
    if (matrix3d) {
      const p = matrix3d[1].split(",").map((n) => Number(n.trim()));
      return {
        x: Number.isFinite(p[12]) ? p[12] : 0,
        y: Number.isFinite(p[13]) ? p[13] : 0,
        scaleX: Math.hypot(p[0] || 1, p[1] || 0, p[2] || 0) || 1,
        scaleY: Math.hypot(p[4] || 0, p[5] || 1, p[6] || 0) || 1,
        rotation: (Math.atan2(p[1] || 0, p[0] || 1) * 180) / Math.PI,
      };
    }
    return { x: 0, y: 0, scaleX: 1, scaleY: 1, rotation: 0 };
  }

  function buildTransform(state) {
    const x = Number(state.x) || 0;
    const y = Number(state.y) || 0;
    const scaleX = Number.isFinite(Number(state.scaleX))
      ? Number(state.scaleX)
      : Number.isFinite(Number(state.scale))
        ? Number(state.scale)
        : 1;
    const scaleY = Number.isFinite(Number(state.scaleY))
      ? Number(state.scaleY)
      : Number.isFinite(Number(state.scale))
        ? Number(state.scale)
        : 1;
    const rotation = Number(state.rotation) || 0;
    return `translate3d(${x}px, ${y}px, 0px) rotate(${rotation}deg) scale(${scaleX}, ${scaleY})`;
  }

  function captureBase(target) {
    if (baseCache.has(target)) return baseCache.get(target);
    let base;
    if (isElement(target)) {
      const style = getComputedStyle(target);
      const transform = parseTransform(style.transform);
      base = {
        opacity: Number(style.opacity) || 0,
        width: style.width,
        height: style.height,
        color: style.color,
        backgroundColor: style.backgroundColor,
        borderColor: style.borderColor,
        borderTopColor: style.borderTopColor,
        borderRightColor: style.borderRightColor,
        borderBottomColor: style.borderBottomColor,
        borderLeftColor: style.borderLeftColor,
        filter: style.filter,
        x: transform.x,
        y: transform.y,
        scaleX: transform.scaleX,
        scaleY: transform.scaleY,
        scale: (transform.scaleX + transform.scaleY) / 2,
        rotation: transform.rotation,
      };
    } else if (target && typeof target === "object") {
      base = { ...target };
    } else {
      base = {};
    }
    baseCache.set(target, base);
    return base;
  }

  function cloneState(base) {
    return { ...base };
  }

  function easeFromName(name) {
    const easeName = String(name || "none").trim();
    if (!easeName || easeName === "none" || easeName === "linear") {
      return (t) => t;
    }
    const match = easeName.match(/^power(\d+)\.(in|out|inOut)$/i);
    if (match) {
      const power = Number(match[1]) || 1;
      const mode = match[2].toLowerCase();
      if (mode === "in") return (t) => Math.pow(t, power);
      if (mode === "out") return (t) => 1 - Math.pow(1 - t, power);
      return (t) =>
        t < 0.5
          ? Math.pow(t * 2, power) / 2
          : 1 - Math.pow((1 - t) * 2, power) / 2;
    }
    if (easeName === "power1.out") return (t) => t;
    return (t) => t;
  }

  function interpolateValue(prop, from, to, t) {
    if (prop === "scale") {
      const start = Number(from);
      const end = Number(to);
      return start + (end - start) * t;
    }
    if (prop === "x" || prop === "y" || prop === "scaleX" || prop === "scaleY" || prop === "rotation") {
      const start = Number(from) || 0;
      const end = Number(to) || 0;
      return start + (end - start) * t;
    }
    const fromColor = parseColor(from);
    const toColor = parseColor(to);
    if (fromColor && toColor) {
      return colorToString({
        r: fromColor.r + (toColor.r - fromColor.r) * t,
        g: fromColor.g + (toColor.g - fromColor.g) * t,
        b: fromColor.b + (toColor.b - fromColor.b) * t,
        a: fromColor.a + (toColor.a - fromColor.a) * t,
      });
    }
    const fromNum = parseNumberUnit(from);
    const toNum = parseNumberUnit(to);
    if (fromNum && toNum) {
      const unit = toNum.unit || fromNum.unit;
      const value = fromNum.value + (toNum.value - fromNum.value) * t;
      return `${value}${unit}`;
    }
    if (to == null) return from;
    if (from == null) return to;
    return t < 1 ? from : to;
  }

  function animatedProps(vars) {
    const props = {};
    for (const [key, value] of Object.entries(vars || {})) {
      if (!reserved.has(key)) props[key] = value;
    }
    return props;
  }

  function stateAt(target, time, tweens, callUpdate = false) {
    const state = cloneState(captureBase(target));
    for (const tween of tweens) {
      if (tween.target !== target) continue;
      if (time < tween.start) continue;
      const progress = tween.duration <= 0 ? 1 : clamp((time - tween.start) / tween.duration, 0, 1);
      const eased = tween.easeFn(progress);
      for (const prop of tween.props) {
        const startValue = tween.from[prop];
        const endValue = tween.to[prop];
        if (prop === "scale") {
          const s = interpolateValue(prop, startValue, endValue, eased);
          state.scale = s;
          state.scaleX = s;
          state.scaleY = s;
        } else {
          const value = interpolateValue(prop, startValue, endValue, eased);
          state[prop] = value;
          if (prop === "scaleX" || prop === "scaleY") {
            state.scale = (Number(state.scaleX) + Number(state.scaleY)) / 2;
          }
        }
      }
      if (callUpdate && typeof tween.onUpdate === "function") {
        tween.onUpdate.call(tween.scope || target);
      }
    }
    return state;
  }

  function applyState(target, state) {
    if (isElement(target)) {
      const style = target.style;
      if (state.opacity != null) style.opacity = String(state.opacity);
      if (state.width != null) style.width = String(state.width);
      if (state.height != null) style.height = String(state.height);
      if (state.color != null) style.color = String(state.color);
      if (state.backgroundColor != null) style.backgroundColor = String(state.backgroundColor);
      if (state.borderColor != null) style.borderColor = String(state.borderColor);
      if (state.borderTopColor != null) style.borderTopColor = String(state.borderTopColor);
      if (state.borderRightColor != null) style.borderRightColor = String(state.borderRightColor);
      if (state.borderBottomColor != null) style.borderBottomColor = String(state.borderBottomColor);
      if (state.borderLeftColor != null) style.borderLeftColor = String(state.borderLeftColor);
      if (state.filter != null) style.filter = String(state.filter);
      if (state.x != null || state.y != null || state.scaleX != null || state.scaleY != null || state.rotation != null || state.scale != null) {
        style.transform = buildTransform(state);
      }
    } else if (target && typeof target === "object") {
      for (const [key, value] of Object.entries(state)) {
        if (key.startsWith("__")) continue;
        target[key] = value;
      }
    }
  }

  class MiniTimeline {
    constructor(vars = {}) {
      this.vars = vars || {};
      this.defaults = this.vars.defaults || {};
      this.paused = !!this.vars.paused;
      this._timeScale = Number.isFinite(Number(this.vars.timeScale)) ? Number(this.vars.timeScale) : 1;
      this._tweens = [];
      this._time = 0;
      this._duration = 0;
      this._eventCallbacks = new Map();
      timelines.add(this);
    }

    _resolvePosition(position) {
      if (position == null) return this._duration;
      if (typeof position === "number" && Number.isFinite(position)) return position;
      if (typeof position === "string") {
        const trimmed = position.trim();
        if (trimmed === "<" || trimmed === ">") return this._duration;
        const relative = trimmed.match(/^([+-])=(.*)$/);
        if (relative) {
          const delta = Number(relative[2]) || 0;
          return this._duration + (relative[1] === "-" ? -delta : delta);
        }
        const asNumber = Number(trimmed);
        if (Number.isFinite(asNumber)) return asNumber;
      }
      return this._duration;
    }

    _captureTween(target, start, duration, fromVars, toVars) {
      const base = stateAt(target, start, this._tweens, false);
      const from = {};
      const to = {};
      const props = new Set([
        ...Object.keys(fromVars || {}),
        ...Object.keys(toVars || {}),
      ]);
      for (const prop of props) {
        if (reserved.has(prop)) continue;
        const hasFrom = fromVars && Object.prototype.hasOwnProperty.call(fromVars, prop);
        const hasTo = toVars && Object.prototype.hasOwnProperty.call(toVars, prop);
        if (hasFrom) {
          from[prop] = fromVars[prop];
        } else {
          from[prop] = base[prop];
        }
        if (hasTo) {
          to[prop] = toVars[prop];
        } else {
          to[prop] = base[prop];
        }
      }
      return { from, to, props: Array.from(props).filter((prop) => !reserved.has(prop)) };
    }

    _pushTween(target, start, duration, fromVars, toVars, opts = {}) {
      const tween = this._captureTween(target, start, duration, fromVars, toVars);
      tween.target = target;
      tween.start = start;
      tween.duration = duration;
      tween.easeFn = easeFromName(opts.ease ?? toVars?.ease ?? fromVars?.ease ?? this.defaults.ease ?? "none");
      tween.onUpdate = opts.onUpdate ?? toVars?.onUpdate ?? fromVars?.onUpdate ?? null;
      tween.scope = opts.scope ?? target;
      this._tweens.push(tween);
      this._duration = Math.max(this._duration, start + duration);
    }

    _schedule(kind, targets, fromVars, toVars, position) {
      const list = toArray(targets);
      const resolvedPosition = this._resolvePosition(position);
      const stagger = Number((toVars && toVars.stagger) ?? (fromVars && fromVars.stagger) ?? 0) || 0;
      const duration = Number((toVars && toVars.duration) ?? (fromVars && fromVars.duration) ?? this.defaults.duration ?? 0) || 0;
      list.forEach((target, index) => {
        const start = resolvedPosition + index * stagger;
        if (kind === "set") {
          this._pushTween(target, start, 0, {}, toVars || {}, { onUpdate: toVars?.onUpdate, scope: target, ease: "none" });
          return;
        }
        if (kind === "fromTo") {
          this._pushTween(target, start, duration, fromVars || {}, toVars || {}, { onUpdate: toVars?.onUpdate, scope: target });
          return;
        }
        if (kind === "to") {
          this._pushTween(target, start, duration, {}, toVars || {}, { onUpdate: toVars?.onUpdate, scope: target });
          return;
        }
        if (kind === "from") {
          this._pushTween(target, start, duration, fromVars || {}, {}, { onUpdate: fromVars?.onUpdate, scope: target });
        }
      });
      return this;
    }

    to(targets, vars = {}, position) {
      return this._schedule("to", targets, null, vars, position);
    }

    fromTo(targets, fromVars = {}, toVars = {}, position) {
      return this._schedule("fromTo", targets, fromVars, toVars, position);
    }

    from(targets, vars = {}, position) {
      return this._schedule("from", targets, vars, null, position);
    }

    set(targets, vars = {}, position) {
      return this._schedule("set", targets, null, vars, position);
    }

    add(item, position = 0) {
      if (item instanceof MiniTimeline) {
        const offset = this._resolvePosition(position);
        for (const tween of item._tweens) {
          this._tweens.push({
            ...tween,
            from: { ...tween.from },
            to: { ...tween.to },
            start: tween.start + offset,
          });
        }
        this._duration = Math.max(this._duration, offset + item.totalDuration());
        return this;
      }
      if (typeof item === "function") {
        item.call(this);
      }
      return this;
    }

    clear() {
      this._tweens.length = 0;
      this._duration = 0;
      this._time = 0;
      return this;
    }

    kill() {
      timelines.delete(this);
      return this;
    }

    pause() {
      this.paused = true;
      return this;
    }

    play() {
      this.paused = false;
      return this;
    }

    timeScale(value) {
      if (arguments.length === 0) return this._timeScale;
      const next = Number(value);
      if (Number.isFinite(next)) this._timeScale = next;
      return this;
    }

    totalTime(time) {
      if (arguments.length === 0) return this._time;
      return this.seek(time);
    }

    seek(time) {
      this._time = clamp(Number(time) || 0, 0, this._duration || 0);
      this._render(this._time);
      return this;
    }

    time(time) {
      if (arguments.length === 0) return this._time;
      return this.seek(time);
    }

    progress(value) {
      if (arguments.length === 0) {
        return this._duration ? this._time / this._duration : 0;
      }
      return this.seek((Number(value) || 0) * (this._duration || 0));
    }

    duration() {
      return this._duration;
    }

    totalDuration() {
      return this._duration;
    }

    getChildren() {
      return this._tweens.map((tween) => ({
        parent: null,
        targets: () => toArray(tween.target),
        startTime: () => tween.start,
        duration: () => tween.duration,
      }));
    }

    eventCallback(name, callback) {
      if (arguments.length === 1) return this._eventCallbacks.get(name) || null;
      if (typeof callback !== "function") {
        this._eventCallbacks.delete(name);
        return this;
      }
      this._eventCallbacks.set(name, callback);
      return this;
    }

    _render(time) {
      const byTarget = new Map();
      for (const tween of this._tweens) {
        if (!byTarget.has(tween.target)) byTarget.set(tween.target, []);
        byTarget.get(tween.target).push(tween);
      }
      for (const [target, tweens] of byTarget) {
        const state = cloneState(captureBase(target));
        for (const tween of tweens) {
          if (time < tween.start) continue;
          const progress = tween.duration <= 0 ? 1 : clamp((time - tween.start) / tween.duration, 0, 1);
          const eased = tween.easeFn(progress);
          for (const prop of tween.props) {
            const startValue = tween.from[prop];
            const endValue = tween.to[prop];
            if (prop === "scale") {
              const s = interpolateValue(prop, startValue, endValue, eased);
              state.scale = s;
              state.scaleX = s;
              state.scaleY = s;
            } else {
              state[prop] = interpolateValue(prop, startValue, endValue, eased);
              if (prop === "scaleX" || prop === "scaleY") {
                state.scale = (Number(state.scaleX) + Number(state.scaleY)) / 2;
              }
            }
          }
          if (typeof tween.onUpdate === "function") {
            tween.onUpdate.call(tween.scope || target);
          }
        }
        applyState(target, state);
      }
      if (time >= this._duration) {
        const onComplete = this._eventCallbacks.get("onComplete");
        if (typeof onComplete === "function") {
          try {
            onComplete.call(this);
          } catch {
            /* ignore */
          }
        }
      }
      return this;
    }
  }

  function makeTimeline(vars) {
    return new MiniTimeline(vars);
  }

  function applyImmediate(targets, vars) {
    const list = toArray(targets);
    for (const target of list) {
      const tl = new MiniTimeline({ paused: true });
      tl.set(target, vars, 0);
      tl.seek(0);
      tl.kill();
    }
    return targets;
  }

  const gsap = {
    timeline: (vars) => makeTimeline(vars),
    to: (targets, vars = {}) => makeTimeline({ paused: true }).to(targets, vars, 0),
    fromTo: (targets, fromVars = {}, toVars = {}) => makeTimeline({ paused: true }).fromTo(targets, fromVars, toVars, 0),
    from: (targets, vars = {}) => makeTimeline({ paused: true }).from(targets, vars, 0),
    set: (targets, vars = {}) => applyImmediate(targets, vars),
    registerPlugin: () => {},
    config: () => {},
    defaults: () => {},
    killTweensOf: () => {},
    matchMedia: () => ({
      add: (query, fn) => {
        if (typeof fn === "function") fn();
        return gsap.matchMedia();
      },
      revert: () => {},
    }),
    utils: {
      clamp,
      toArray,
      mapRange: function (inMin, inMax, outMin, outMax, value) {
        if (arguments.length < 5) {
          return (v) => gsap.utils.mapRange(inMin, inMax, outMin, outMax, v);
        }
        const p = (value - inMin) / (inMax - inMin || 1);
        return outMin + (outMax - outMin) * p;
      },
      normalize: function (min, max, value) {
        if (arguments.length < 3) return (v) => gsap.utils.normalize(min, max, v);
        return (value - min) / (max - min || 1);
      },
      interpolate: (from, to, progress) => from + (to - from) * progress,
      wrap: function (min, max, value) {
        if (arguments.length < 3) return (v) => gsap.utils.wrap(min, max, v);
        const range = max - min;
        if (!range) return min;
        const wrapped = ((value - min) % range + range) % range;
        return min + wrapped;
      },
      pipe: (...fns) => (value) => fns.reduce((acc, fn) => fn(acc), value),
      snap: function (increment, value) {
        if (arguments.length < 2) return (v) => gsap.utils.snap(increment, v);
        return Math.round(value / increment) * increment;
      },
      random: (min = 0, max = 1, round = false) => {
        const value = min + Math.random() * (max - min);
        return round ? Math.round(value) : value;
      },
    },
    ticker: {
      _callbacks: new Set(),
      add(fn) {
        if (typeof fn === "function") this._callbacks.add(fn);
        return fn;
      },
      remove(fn) {
        this._callbacks.delete(fn);
      },
      tick() {
        for (const fn of this._callbacks) {
          try {
            fn();
          } catch {
            /* ignore */
          }
        }
        for (const tl of timelines) {
          if (typeof tl._time === "number") tl._render(tl._time);
        }
      },
      lagSmoothing: () => {},
    },
  };

  win.gsap = gsap;
})();
